external_knowledge:
- 'Technology giants' refers to companies in the 'Technology' sector with a market capitalization greater than $100 billion; 
- 'consistent players' implies companies that have trading data available for the first quarter of 2023, as indicated by the presence of stock data for this period; 
- 'active price alert' means an alert that is currently active (i.e., not triggered) and pertains to the price of the stock.

sql:
SELECT (
  SELECT GROUP_CONCAT(
    'User: ' || u.user_name || ', Alert Message: ' || a.alert_message || ', Company: ' || c.company_name
  )
  FROM users u
  INNER JOIN alerts a ON u.user_id = a.user_id
  INNER JOIN companies c ON a.company_id = c.company_id
  WHERE a.alert_status = 'active' AND u.user_id IN (
    SELECT DISTINCT p.user_id
    FROM portfolios p
  )
) AS alert_details;
